        }).orElse(ResponseEntity.notFound().build());
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<?> deletar(@PathVariable Long id) {
        return cargaRepository.findById(id).map(c -> {
            cargaRepository.delete(c);
            return ResponseEntity.ok().build();
        }).orElse(ResponseEntity.notFound().build());
    }
}

package com.transportadora.logistica.controller;

import com.transportadora.logistica.model.Viagem;
import com.transportadora.logistica.model.Veiculo;
import com.transportadora.logistica.model.Rota;
import com.transportadora.logistica.model.Carga;
import com.transportadora.logistica.repository.ViagemRepository;
import com.transportadora.logistica.repository.VeiculoRepository;
import com.transportadora.logistica.repository.RotaRepository;
import com.transportadora.logistica.repository.CargaRepository;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.time.LocalDateTime;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/viagens")
public class ViagemController {

    private final ViagemRepository viagemRepository;
    private final VeiculoRepository veiculoRepository;
    private final RotaRepository rotaRepository;
    private final CargaRepository cargaRepository;

    public ViagemController(ViagemRepository viagemRepository,
                            VeiculoRepository veiculoRepository,
                            RotaRepository rotaRepository,
                            CargaRepository cargaRepository) {
        this.viagemRepository = viagemRepository;
        this.veiculoRepository = veiculoRepository;
        this.rotaRepository = rotaRepository;
        this.cargaRepository = cargaRepository;
    }

    @GetMapping
    public List<Viagem> listar() {
        return viagemRepository.findAll();
    }

    @GetMapping("/{id}")
    public ResponseEntity<Viagem> buscar(@PathVariable Long id) {
        return viagemRepository.findById(id)
                .map(ResponseEntity::ok)
                .orElse(ResponseEntity.notFound().build());
    }

    @PostMapping
    public ResponseEntity<?> criar(@RequestBody Map<String, Object> dados) {
        Viagem viagem = new Viagem();

        Long veiculoId = Long.valueOf(dados.get("veiculoId").toString());
        Long rotaId = Long.valueOf(dados.get("rotaId").toString());
        Long cargaId = Long.valueOf(dados.get("cargaId").toString());

        Veiculo veiculo = veiculoRepository.findById(veiculoId).orElse(null);
        Rota rota = rotaRepository.findById(rotaId).orElse(null);
        Carga carga = cargaRepository.findById(cargaId).orElse(null);

        if (veiculo == null || rota == null || carga == null) {
            return ResponseEntity.badRequest().body(Map.of("erro", "Veiculo, rota ou carga nao encontrados"));
        }

        viagem.setVeiculo(veiculo);
        viagem.setRota(rota);
        viagem.setCarga(carga);
        viagem.setMotorista(dados.get("motorista").toString());
        viagem.setDataPartida(LocalDateTime.parse(dados.get("dataPartida").toString()));

        if (dados.containsKey("dataChegadaPrevista") && dados.get("dataChegadaPrevista") != null) {
            viagem.setDataChegadaPrevista(LocalDateTime.parse(dados.get("dataChegadaPrevista").toString()));
        }

        viagem.setObservacoes(dados.getOrDefault("observacoes", "").toString());

        // Atualizar status do veiculo
        veiculo.setStatus(Veiculo.StatusVeiculo.EM_VIAGEM);
        veiculoRepository.save(veiculo);

        return ResponseEntity.ok(viagemRepository.save(viagem));
    }

    @PatchMapping("/{id}/status")
    public ResponseEntity<?> atualizarStatus(@PathVariable Long id, @RequestBody Map<String, String> dados) {
        return viagemRepository.findById(id).map(v -> {
            Viagem.StatusViagem novoStatus = Viagem.StatusViagem.valueOf(dados.get("status"));
            v.setStatus(novoStatus);

            if (novoStatus == Viagem.StatusViagem.ENTREGUE) {
                v.setDataChegadaReal(LocalDateTime.now());
                // Liberar veiculo
                if (v.getVeiculo() != null) {
                    v.getVeiculo().setStatus(Veiculo.StatusVeiculo.DISPONIVEL);
                    veiculoRepository.save(v.getVeiculo());
                }
            } else if (novoStatus == Viagem.StatusViagem.CANCELADA && v.getVeiculo() != null) {
                v.getVeiculo().setStatus(Veiculo.StatusVeiculo.DISPONIVEL);
                veiculoRepository.save(v.getVeiculo());
            }

            return ResponseEntity.ok(viagemRepository.save(v));
        }).orElse(ResponseEntity.notFound().build());
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<?> deletar(@PathVariable Long id) {
        return viagemRepository.findById(id).map(v -> {
            viagemRepository.delete(v);
            return ResponseEntity.ok().build();
        }).orElse(ResponseEntity.notFound().build());
    }
}

package com.transportadora.logistica.controller;

import com.transportadora.logistica.model.Frete;
import com.transportadora.logistica.service.FreteService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/fretes")
public class FreteController {

    private final FreteService freteService;

    public FreteController(FreteService freteService) {
        this.freteService = freteService;
    }

    @PostMapping("/calcular")
    public ResponseEntity<Frete> calcular(@RequestBody Map<String, Object> dados) {
        double distancia = Double.parseDouble(dados.get("distanciaKm").toString());
        double peso = Double.parseDouble(dados.get("pesoKg").toString());
        String tipoCarga = dados.getOrDefault("tipoCarga", "GERAL").toString();
        double pedagio = Double.parseDouble(dados.getOrDefault("custoPedagio", "0").toString());
        double margem = Double.parseDouble(dados.getOrDefault("margemLucro", "15").toString());

        Frete frete = freteService.calcularESalvar(distancia, peso, tipoCarga, pedagio, margem);
        return ResponseEntity.ok(frete);
    }

    @PostMapping("/simular")
    public ResponseEntity<Frete> simular(@RequestBody Map<String, Object> dados) {
        double distancia = Double.parseDouble(dados.get("distanciaKm").toString());
        double peso = Double.parseDouble(dados.get("pesoKg").toString());
        String tipoCarga = dados.getOrDefault("tipoCarga", "GERAL").toString();
        double pedagio = Double.parseDouble(dados.getOrDefault("custoPedagio", "0").toString());
        double margem = Double.parseDouble(dados.getOrDefault("margemLucro", "15").toString());

        Frete frete = freteService.calcularFrete(distancia, peso, tipoCarga, pedagio, margem);
        return ResponseEntity.ok(frete);
    }

    @GetMapping
    public List<Frete> listar() {
        return freteService.listarTodos();
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<?> deletar(@PathVariable Long id) {
        freteService.deletar(id);
        return ResponseEntity.ok().build();
    }
}

