.calc-container {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 24px;
}

.calc-form {
    background: white;
    border-radius: 10px;
    padding: 24px;
    box-shadow: var(--shadow);
}

.calc-result {
    background: white;
    border-radius: 10px;
    padding: 24px;
    box-shadow: var(--shadow);
}

.result-item {
    display: flex;
    justify-content: space-between;
