    public void setCnh(String cnh) { this.cnh = cnh; }

    public CategoriaCNH getCategoriaCnh() { return categoriaCnh; }
    public void setCategoriaCnh(CategoriaCNH categoriaCnh) { this.categoriaCnh = categoriaCnh; }

